'use server';

import { generateKissVideo, type GenerateKissVideoInput } from '@/ai/flows/generate-kiss-video';

export async function createKissVideoAction(
  input: GenerateKissVideoInput
): Promise<{ videoDataUri?: string; error?: string }> {
  if (!process.env.GEMINI_API_KEY || process.env.GEMINI_API_KEY === 'YOUR_API_KEY_HERE') {
    return { error: 'Clé API Gemini manquante. Veuillez la configurer dans le fichier .env à la racine du projet.' };
  }
  
  try {
    const result = await generateKissVideo(input);
    if (!result.videoDataUri) {
      return { error: 'The AI failed to return a video. Please try again.' };
    }
    return { videoDataUri: result.videoDataUri };
  } catch (e) {
    console.error('Video generation error:', e);
    const message = e instanceof Error ? e.message : 'An unknown error occurred.';
    
    if (message.includes('quota')) {
        return { error: 'We are experiencing high demand. Please try again later.' };
    }
    if (message.includes('Invalid argument') || message.includes('could not process the image')) {
        return { error: 'The AI could not process the image(s). Please try different photos.' };
    }
    if (message.includes('API key not valid') || message.includes('API key is invalid')) {
        return { error: 'Votre clé API Gemini n\'est pas valide. Veuillez la vérifier dans votre fichier .env.' };
    }
     if (message.includes('FAILED_PRECONDITION') || message.includes('GEMINI_API_KEY')) {
        return { error: 'FAILED_PRECONDITION: La clé API Gemini semble incorrecte ou manquante. Veuillez vérifier votre fichier .env.' };
    }
    
    return { error: `An unexpected error occurred: ${message}` };
  }
}
